#Requires -Version 5.0\n\n<#\n.SYNOPSIS\n    Script de compilación optimizado para Gestor de Créditos en Windows\n    Compila ambas versiones: Admin e Invitado\n\n.DESCRIPTION\n    Este script automatiza la compilación de ambas versiones (Admin e Invitado)\n    del Gestor de Créditos para Android usando EAS CLI.\n    Incluye verificación de requisitos, compilación paralela, y gestión de errores.\n\n.PARAMETER Action\n    Acción a realizar: all, admin, guest, gradle, install, clean, report, help\n\n.PARAMETER Parallel\n    Compilar ambas versiones en paralelo (experimental)\n\n.PARAMETER Verbose\n    Mostrar salida detallada\n\n.EXAMPLE\n    .\\compile-windows.ps1\n    .\\compile-windows.ps1 -Action admin\n    .\\compile-windows.ps1 -Action all -Parallel\n    .\\compile-windows.ps1 -Action install\n\n#>\n\nparam(\n    [Parameter(Position = 0)]\n    [ValidateSet('all', 'admin', 'guest', 'gradle', 'install', 'clean', 'report', 'help')]\n    [string]$Action = 'all',\n    \n    [switch]$Parallel = $false,\n    [switch]$Verbose = $false\n)\n\n# Variables globales\n$ProjectDir = Get-Location\n$AppJson = \"app.json\"\n$AppGuestJson = \"app-guest.json\"\n$OutputDir = \".\\dist\\apks\"\n$BuildLog = \".\\dist\\build.log\"\n$ReportFile = \".\\dist\\build-report-$(Get-Date -Format 'yyyy-MM-dd_HH-mm-ss').txt\"\n$Timestamp = Get-Date -Format \"yyyy-MM-dd_HH-mm-ss\"\n$StartTime = Get-Date\n\n# Configuración de colores\n$Colors = @{\n    Red     = 'Red'\n    Green   = 'Green'\n    Yellow  = 'Yellow'\n    Blue    = 'Blue'\n    Cyan    = 'Cyan'\n    Magenta = 'Magenta'\n    Gray    = 'Gray'\n}\n\n################################################################################\n# FUNCIONES DE UTILIDAD\n################################################################################\n\nfunction Write-Header {\n    param([string]$Message, [string]$Color = 'Blue')\n    Write-Host \"`n\" -NoNewline\n    Write-Host \"╔════════════════════════════════════════════════════════════╗\" -ForegroundColor $Color\n    Write-Host \"║ $Message\" -ForegroundColor $Color\n    Write-Host \"╚════════════════════════════════════════════════════════════╝\" -ForegroundColor $Color\n}\n\nfunction Write-Section {\n    param([string]$Message, [string]$Icon = '📦')\n    Write-Host \"`n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\" -ForegroundColor Yellow\n    Write-Host \"$Icon $Message\" -ForegroundColor Yellow\n    Write-Host \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\" -ForegroundColor Yellow\n}\n\nfunction Write-Success {\n    param([string]$Message)\n    Write-Host \"✅ $Message\" -ForegroundColor Green\n}\n\nfunction Write-Error-Custom {\n    param([string]$Message)\n    Write-Host \"❌ $Message\" -ForegroundColor Red\n}\n\nfunction Write-Info {\n    param([string]$Message)\n    Write-Host \"ℹ️  $Message\" -ForegroundColor Blue\n}\n\nfunction Write-Warning-Custom {\n    param([string]$Message)\n    Write-Host \"⚠️  $Message\" -ForegroundColor Yellow\n}\n\nfunction Write-Debug-Custom {\n    param([string]$Message)\n    if ($Verbose) {\n        Write-Host \"🔍 $Message\" -ForegroundColor Cyan\n    }\n}\n\nfunction Test-CommandExists {\n    param([string]$Command)\n    $null = Get-Command $Command -ErrorAction SilentlyContinue\n    return $?\n}\n\nfunction Log-Message {\n    param([string]$Message, [string]$Level = 'INFO')\n    $logEntry = \"[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] [$Level] $Message\"\n    Add-Content -Path $BuildLog -Value $logEntry -ErrorAction SilentlyContinue\n}\n\nfunction Get-ElapsedTime {\n    $elapsed = (Get-Date) - $StartTime\n    return \"{0:hh\\:mm\\:ss}\" -f $elapsed\n}\n\n################################################################################\n# VERIFICACIÓN DE REQUISITOS\n################################################################################\n\nfunction Check-Requirements {\n    Write-Section \"Verificando Requisitos\" \"✓\"\n    \n    $allOk = $true\n    \n    # Verificar Node.js\n    if (Test-CommandExists node) {\n        $nodeVersion = & node --version\n        Write-Success \"Node.js $nodeVersion encontrado\"\n        Log-Message \"Node.js $nodeVersion encontrado\"\n    } else {\n        Write-Error-Custom \"Node.js no está instalado\"\n        Write-Info \"Instala Node.js desde: https://nodejs.org\"\n        Log-Message \"Node.js no encontrado\" \"ERROR\"\n        $allOk = $false\n    }\n    \n    # Verificar npm\n    if (Test-CommandExists npm) {\n        $npmVersion = & npm --version\n        Write-Success \"npm $npmVersion encontrado\"\n        Log-Message \"npm $npmVersion encontrado\"\n    } else {\n        Write-Error-Custom \"npm no está instalado\"\n        Log-Message \"npm no encontrado\" \"ERROR\"\n        $allOk = $false\n    }\n    \n    # Verificar EAS CLI\n    if (Test-CommandExists eas) {\n        $easVersion = & eas --version\n        Write-Success \"EAS CLI $easVersion encontrado\"\n        Log-Message \"EAS CLI $easVersion encontrado\"\n    } else {\n        Write-Error-Custom \"EAS CLI no está instalado\"\n        Write-Info \"Instala con: npm install -g eas-cli\"\n        Log-Message \"EAS CLI no encontrado\" \"ERROR\"\n        $allOk = $false\n    }\n    \n    # Verificar archivos de configuración\n    if (-not (Test-Path $AppJson)) {\n        Write-Error-Custom \"$AppJson no encontrado\"\n        Log-Message \"$AppJson no encontrado\" \"ERROR\"\n        $allOk = $false\n    } else {\n        Write-Success \"$AppJson encontrado\"\n        Log-Message \"$AppJson encontrado\"\n    }\n    \n    if (-not (Test-Path $AppGuestJson)) {\n        Write-Error-Custom \"$AppGuestJson no encontrado\"\n        Log-Message \"$AppGuestJson no encontrado\" \"ERROR\"\n        $allOk = $false\n    } else {\n        Write-Success \"$AppGuestJson encontrado\"\n        Log-Message \"$AppGuestJson encontrado\"\n    }\n    \n    if (-not $allOk) {\n        Write-Error-Custom \"Algunos requisitos no se cumplen\"\n        exit 1\n    }\n    \n    Write-Success \"Todos los requisitos verificados\"\n    Log-Message \"Todos los requisitos verificados\"\n}\n\n################################################################################\n# CONFIGURACIÓN DEL AMBIENTE\n################################################################################\n\nfunction Setup-Environment {\n    Write-Section \"Configurando Ambiente\" \"⚙️\"\n    \n    # Crear directorio de salida\n    if (-not (Test-Path $OutputDir)) {\n        New-Item -ItemType Directory -Path $OutputDir -Force | Out-Null\n        Write-Success \"Directorio de salida creado: $OutputDir\"\n        Log-Message \"Directorio de salida creado: $OutputDir\"\n    } else {\n        Write-Info \"Directorio de salida ya existe\"\n    }\n    \n    # Crear directorio dist si no existe\n    if (-not (Test-Path \".\\dist\")) {\n        New-Item -ItemType Directory -Path \".\\dist\" -Force | Out-Null\n    }\n    \n    # Inicializar log\n    \"\" | Out-File -FilePath $BuildLog -Force\n    Write-Success \"Log de compilación inicializado\"\n    Log-Message \"=== COMPILACIÓN INICIADA ===\"\n    Log-Message \"Timestamp: $Timestamp\"\n    Log-Message \"Directorio de proyecto: $ProjectDir\"\n}\n\n################################################################################\n# INSTALACIÓN DE DEPENDENCIAS\n################################################################################\n\nfunction Install-Dependencies {\n    Write-Section \"Instalando Dependencias\" \"📚\"\n    \n    if (Test-Path \"node_modules\") {\n        Write-Info \"node_modules ya existe. Limpiando...\"\n        Remove-Item -Path \"node_modules\" -Recurse -Force -ErrorAction SilentlyContinue\n        Remove-Item -Path \"package-lock.json\" -Force -ErrorAction SilentlyContinue\n        Log-Message \"node_modules limpiado\"\n    }\n    \n    Write-Info \"Ejecutando: npm install\"\n    Log-Message \"Ejecutando: npm install\"\n    \n    $output = & npm install 2>&1\n    $output | Out-File -FilePath $BuildLog -Append\n    \n    if ($LASTEXITCODE -eq 0) {\n        Write-Success \"Dependencias instaladas\"\n        Log-Message \"Dependencias instaladas correctamente\"\n    } else {\n        Write-Error-Custom \"Error al instalar dependencias\"\n        Log-Message \"Error al instalar dependencias\" \"ERROR\"\n        exit 1\n    }\n}\n\n################################################################################\n# COMPILACIÓN\n################################################################################\n\nfunction Build-Admin {\n    Write-Section \"Compilando Versión ADMIN\" \"🔧\"\n    \n    # Asegurar que estamos usando app.json\n    if (Test-Path \"app.json.backup\") {\n        Copy-Item -Path \"app.json.backup\" -Destination \"app.json\" -Force\n    }\n    \n    Write-Info \"Configuración: $AppJson\"\n    Write-Info \"Package: com.gestorcreditos.admin\"\n    Write-Info \"Versión: 1.0.0-admin\"\n    Log-Message \"Compilando versión Admin\"\n    \n    Write-Info \"Ejecutando: eas build --platform android --local\"\n    Log-Message \"Ejecutando: eas build --platform android --local\"\n    \n    $output = & eas build --platform android --local 2>&1\n    $output | Out-File -FilePath $BuildLog -Append\n    \n    if ($LASTEXITCODE -eq 0) {\n        Write-Success \"APK Admin compilado exitosamente\"\n        Log-Message \"APK Admin compilado exitosamente\"\n        \n        # Buscar y copiar APK\n        $apks = Get-ChildItem -Path \".\" -Filter \"*admin*.apk\" -Recurse -ErrorAction SilentlyContinue\n        if ($apks) {\n            foreach ($apk in $apks) {\n                $destPath = Join-Path $OutputDir \"gestor-creditos-admin-$Timestamp.apk\"\n                Copy-Item -Path $apk.FullName -Destination $destPath -Force\n                Write-Success \"APK copiado a: $destPath\"\n                Log-Message \"APK Admin copiado a: $destPath\"\n            }\n        }\n        return $true\n    } else {\n        Write-Error-Custom \"Error al compilar Admin\"\n        Log-Message \"Error al compilar Admin\" \"ERROR\"\n        return $false\n    }\n}\n\nfunction Build-Guest {\n    Write-Section \"Compilando Versión INVITADO\" \"👥\"\n    \n    # Cambiar a configuración de invitado\n    Copy-Item -Path \"app.json\" -Destination \"app.json.backup\" -Force\n    Copy-Item -Path $AppGuestJson -Destination \"app.json\" -Force\n    \n    Write-Info \"Configuración: $AppGuestJson\"\n    Write-Info \"Package: com.gestorcreditos.guest\"\n    Write-Info \"Versión: 1.0.0-guest\"\n    Log-Message \"Compilando versión Invitado\"\n    \n    # Limpiar build anterior\n    Write-Info \"Limpiando build anterior...\"\n    Remove-Item -Path \"node_modules\" -Recurse -Force -ErrorAction SilentlyContinue\n    Remove-Item -Path \"package-lock.json\" -Force -ErrorAction SilentlyContinue\n    Log-Message \"Build anterior limpiado\"\n    \n    # Reinstalar dependencias\n    Write-Info \"Reinstalando dependencias...\"\n    $output = & npm install 2>&1\n    $output | Out-File -FilePath $BuildLog -Append\n    \n    Write-Info \"Ejecutando: eas build --platform android --local\"\n    Log-Message \"Ejecutando: eas build --platform android --local\"\n    \n    $output = & eas build --platform android --local 2>&1\n    $output | Out-File -FilePath $BuildLog -Append\n    \n    if ($LASTEXITCODE -eq 0) {\n        Write-Success \"APK Invitado compilado exitosamente\"\n        Log-Message \"APK Invitado compilado exitosamente\"\n        \n        # Buscar y copiar APK\n        $apks = Get-ChildItem -Path \".\" -Filter \"*guest*.apk\" -Recurse -ErrorAction SilentlyContinue\n        if ($apks) {\n            foreach ($apk in $apks) {\n                $destPath = Join-Path $OutputDir \"gestor-creditos-guest-$Timestamp.apk\"\n                Copy-Item -Path $apk.FullName -Destination $destPath -Force\n                Write-Success \"APK copiado a: $destPath\"\n                Log-Message \"APK Invitado copiado a: $destPath\"\n            }\n        }\n        \n        # Restaurar configuración original\n        if (Test-Path \"app.json.backup\") {\n            Copy-Item -Path \"app.json.backup\" -Destination \"app.json\" -Force\n            Remove-Item -Path \"app.json.backup\" -Force\n            Write-Success \"Configuración original restaurada\"\n            Log-Message \"Configuración original restaurada\"\n        }\n        \n        return $true\n    } else {\n        Write-Error-Custom \"Error al compilar Invitado\"\n        Log-Message \"Error al compilar Invitado\" \"ERROR\"\n        \n        # Restaurar configuración original\n        if (Test-Path \"app.json.backup\") {\n            Copy-Item -Path \"app.json.backup\" -Destination \"app.json\" -Force\n            Remove-Item -Path \"app.json.backup\" -Force\n        }\n        \n        return $false\n    }\n}\n\n################################################################################\n# INSTALACIÓN EN DISPOSITIVO\n################################################################################\n\nfunction Install-On-Device {\n    Write-Section \"Instalación en Dispositivo\" \"📱\"\n    \n    if (-not (Test-CommandExists adb)) {\n        Write-Error-Custom \"adb no está instalado\"\n        Write-Info \"Instala Android SDK Tools desde: https://developer.android.com/tools\"\n        Log-Message \"adb no encontrado\" \"ERROR\"\n        return $false\n    }\n    \n    # Verificar dispositivo\n    $devices = & adb devices\n    if ($devices -notmatch \"device$\") {\n        Write-Error-Custom \"No hay dispositivo Android conectado\"\n        Write-Info \"Conecta un dispositivo Android y habilita USB Debugging\"\n        Log-Message \"No hay dispositivo conectado\" \"ERROR\"\n        return $false\n    }\n    \n    Write-Info \"Dispositivo encontrado. Instalando APKs...\"\n    Log-Message \"Dispositivo encontrado. Iniciando instalación\"\n    \n    # Instalar Admin\n    $adminApk = Get-ChildItem -Path $OutputDir -Filter \"gestor-creditos-admin-*.apk\" -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1\n    if ($adminApk) {\n        Write-Info \"Instalando Admin: $($adminApk.Name)\"\n        Log-Message \"Instalando: $($adminApk.Name)\"\n        & adb install -r $adminApk.FullName\n        Write-Success \"Admin instalado\"\n        Log-Message \"Admin instalado\"\n    } else {\n        Write-Warning-Custom \"No se encontró APK Admin\"\n    }\n    \n    # Instalar Guest\n    $guestApk = Get-ChildItem -Path $OutputDir -Filter \"gestor-creditos-guest-*.apk\" -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1\n    if ($guestApk) {\n        Write-Info \"Instalando Invitado: $($guestApk.Name)\"\n        Log-Message \"Instalando: $($guestApk.Name)\"\n        & adb install -r $guestApk.FullName\n        Write-Success \"Invitado instalado\"\n        Log-Message \"Invitado instalado\"\n    } else {\n        Write-Warning-Custom \"No se encontró APK Invitado\"\n    }\n    \n    Write-Success \"Instalación completada\"\n    Log-Message \"Instalación completada\"\n    return $true\n}\n\n################################################################################\n# LIMPIEZA\n################################################################################\n\nfunction Cleanup {\n    Write-Section \"Limpieza\" \"🧹\"\n    \n    Write-Info \"Limpiando archivos temporales...\"\n    Remove-Item -Path \"app.json.backup\" -Force -ErrorAction SilentlyContinue\n    Log-Message \"Limpieza completada\"\n    Write-Success \"Limpieza completada\"\n}\n\n################################################################################\n# REPORTE\n################################################################################\n\nfunction Generate-Report {\n    Write-Section \"Generando Reporte\" \"📊\"\n    \n    $report = @\"\nGESTOR DE CRÉDITOS - REPORTE DE COMPILACIÓN\n═════════════════════════════════════════════════════════════\n\nTiempo de compilación: $(Get-ElapsedTime)\nFecha: $Timestamp\nDirectorio: $ProjectDir\n\nVERSIONES COMPILADAS:\n─────────────────────────────────────────────────────────────\n\n1. VERSIÓN ADMIN\n   Package: com.gestorcreditos.admin\n   Versión: 1.0.0-admin\n   Ubicación: $OutputDir\\gestor-creditos-admin-*.apk\n   Estado: Compilado\n\n2. VERSIÓN INVITADO\n   Package: com.gestorcreditos.guest\n   Versión: 1.0.0-guest\n   Ubicación: $OutputDir\\gestor-creditos-guest-*.apk\n   Estado: Compilado\n\nARCHIVOS GENERADOS:\n─────────────────────────────────────────────────────────────\n\"@\n    \n    $apks = Get-ChildItem -Path $OutputDir -Filter \"*.apk\" -ErrorAction SilentlyContinue\n    if ($apks) {\n        foreach ($apk in $apks) {\n            $sizeMB = [math]::Round($apk.Length / 1MB, 2)\n            $report += \"`n   - $($apk.Name) ($sizeMB MB)\"\n        }\n    }\n    \n    $report += @\"\n\nREQUISITOS VERIFICADOS:\n─────────────────────────────────────────────────────────────\n   ✓ Node.js: $(if (Test-CommandExists node) { & node --version } else { 'No encontrado' })\n   ✓ npm: $(if (Test-CommandExists npm) { & npm --version } else { 'No encontrado' })\n   ✓ EAS CLI: $(if (Test-CommandExists eas) { & eas --version } else { 'No encontrado' })\n\nPRÓXIMOS PASOS:\n─────────────────────────────────────────────────────────────\n   1. Conecta tu dispositivo Android\n   2. Habilita USB Debugging\n   3. Ejecuta: .\\compile-windows.ps1 -Action install\n   4. O copia los APKs manualmente:\n      adb install -r \"$OutputDir\\gestor-creditos-admin-*.apk\"\n      adb install -r \"$OutputDir\\gestor-creditos-guest-*.apk\"\n\nSOPORTE:\n─────────────────────────────────────────────────────────────\n   Email: support@gestorcreditos.com\n   Documentación: Consulta los archivos .md en dist/\n   Logs: $BuildLog\n\n═════════════════════════════════════════════════════════════\nFin del reporte - $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')\n\"@\n    \n    $report | Out-File -FilePath $ReportFile -Force\n    Write-Success \"Reporte generado: $ReportFile\"\n    Log-Message \"Reporte generado: $ReportFile\"\n}\n\n################################################################################\n# AYUDA\n################################################################################\n\nfunction Show-Help {\n    $help = @\"\nGESTOR DE CRÉDITOS - COMPILACIÓN PARA WINDOWS (PowerShell)\n\nUso: .\\compile-windows.ps1 [OPCIONES]\n\nOPCIONES:\n  -Action [acción]     Acción a realizar (predeterminado: all)\n  -Parallel            Compilar ambas versiones en paralelo (experimental)\n  -Verbose             Mostrar salida detallada\n  -Help                Mostrar esta ayuda\n\nACCIONES:\n  all                  Compilar ambas versiones (Admin + Invitado) [DEFAULT]\n  admin                Compilar solo versión Admin\n  guest                Compilar solo versión Invitado\n  gradle               Compilar con Gradle local (requiere Android SDK)\n  install              Instalar APKs en dispositivo conectado\n  clean                Limpiar archivos temporales\n  report               Generar reporte de compilación\n  help                 Mostrar esta ayuda\n\nEJEMPLOS:\n  .\\compile-windows.ps1                        # Compilar ambas versiones\n  .\\compile-windows.ps1 -Action admin          # Solo Admin\n  .\\compile-windows.ps1 -Action guest          # Solo Invitado\n  .\\compile-windows.ps1 -Action install        # Instalar en dispositivo\n  .\\compile-windows.ps1 -Action all -Parallel  # Compilar en paralelo\n  .\\compile-windows.ps1 -Verbose               # Modo detallado\n\nREQUISITOS:\n  - Node.js 18+\n  - npm 8+\n  - EAS CLI\n  - PowerShell 5.0+\n  - Para instalar: adb (Android Debug Bridge)\n  - Para Gradle: Android SDK\n\nTIEMPOS ESTIMADOS:\n  all (secuencial):    30-45 minutos\n  all (paralelo):      20-30 minutos\n  admin (solo):        15-20 minutos\n  guest (solo):        15-20 minutos\n  install:             1-2 minutos\n\nSOLUCIÓN DE PROBLEMAS:\n  - Si falla la compilación, verifica: .\\dist\\build.log\n  - Si no se encuentra adb, instala Android SDK Tools\n  - Si npm falla, ejecuta: npm cache clean --force\n\nDOCUMENTACIÓN:\n  - dist/BUILD_SCRIPTS_GUIDE.md\n  - dist/SETUP_DEPENDENCIES_GUIDE.md\n  - SCRIPTS_README.md\n\n\"@\n    Write-Host $help\n}\n\n################################################################################\n# MAIN\n################################################################################\n\nfunction Main {\n    Write-Header \"GESTOR DE CRÉDITOS - COMPILACIÓN PARA WINDOWS (PowerShell)\" \"Blue\"\n    Write-Info \"Timestamp: $Timestamp\"\n    Write-Info \"Directorio: $ProjectDir\"\n    \n    switch ($Action) {\n        'all' {\n            Check-Requirements\n            Setup-Environment\n            Install-Dependencies\n            \n            if ($Parallel) {\n                Write-Warning-Custom \"Compilación paralela es experimental\"\n                # Compilación paralela (requiere jobs)\n                $adminJob = Start-Job -ScriptBlock { & eas build --platform android --local }\n                Build-Guest\n                Wait-Job -Job $adminJob\n            } else {\n                Build-Admin\n                Build-Guest\n            }\n            \n            Cleanup\n            Generate-Report\n            \n            Write-Section \"✅ COMPILACIÓN COMPLETADA\" \"Green\"\n            Write-Success \"Ambas versiones compiladas exitosamente\"\n            Write-Info \"APKs disponibles en: $OutputDir\"\n            Write-Info \"Tiempo total: $(Get-ElapsedTime)\"\n            Log-Message \"Compilación completada exitosamente\"\n        }\n        'admin' {\n            Check-Requirements\n            Setup-Environment\n            Install-Dependencies\n            Build-Admin\n            Cleanup\n            Generate-Report\n            \n            Write-Section \"✅ COMPILACIÓN COMPLETADA\" \"Green\"\n            Write-Success \"Versión Admin compilada exitosamente\"\n            Write-Info \"Tiempo total: $(Get-ElapsedTime)\"\n        }\n        'guest' {\n            Check-Requirements\n            Setup-Environment\n            Install-Dependencies\n            Build-Guest\n            Cleanup\n            Generate-Report\n            \n            Write-Section \"✅ COMPILACIÓN COMPLETADA\" \"Green\"\n            Write-Success \"Versión Invitado compilada exitosamente\"\n            Write-Info \"Tiempo total: $(Get-ElapsedTime)\"\n        }\n        'install' {\n            Install-On-Device\n            Log-Message \"Instalación completada\"\n        }\n        'clean' {\n            Cleanup\n            Write-Success \"Limpieza completada\"\n            Log-Message \"Limpieza ejecutada\"\n        }\n        'report' {\n            Generate-Report\n            Write-Success \"Reporte generado\"\n        }\n        'help' {\n            Show-Help\n        }\n        default {\n            Write-Error-Custom \"Acción desconocida: $Action\"\n            Show-Help\n            exit 1\n        }\n    }\n}\n\n# Ejecutar main\nMain\n
